customCSS:
/* Rainbow Unicorn - Maximum Fun */
@import url('https://fonts.googleapis.com/css2?family=Fredoka:wght@400;500;600;700&family=Nunito:wght@300;400;600&family=Fira+Code&display=swap');

.cyber-glow {
  background: 
    radial-gradient(ellipse 600px 400px at 20% 10%, rgba(255, 102, 170, 0.1), transparent),
    radial-gradient(ellipse 500px 350px at 50% 50%, rgba(204, 102, 255, 0.08), transparent),
    radial-gradient(ellipse 600px 400px at 80% 90%, rgba(102, 170, 255, 0.06), transparent);
  animation: rainbowShift 10s ease-in-out infinite;
}

@keyframes rainbowShift {
  0%, 100% { filter: hue-rotate(0deg); }
  50% { filter: hue-rotate(30deg); }
}

.stat-card {
  border: 1px solid rgba(204, 102, 255, 0.18);
}

.stat-card::before {
  background: linear-gradient(90deg, #ff66aa, #cc66ff, #66aaff, #55eedd, #66ff88);
  height: 3px;
}

.stat-card:hover {
  border-color: rgba(255, 102, 170, 0.35);
  box-shadow: 
    0 4px 25px rgba(204, 102, 255, 0.15),
    0 0 40px rgba(255, 102, 170, 0.08);
}

.stat-value {
  text-shadow: 0 0 20px currentColor;
}

.celebration-title {
  background: linear-gradient(135deg, #ff66aa, #cc66ff, #66aaff, #66ff88);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(204, 102, 255, 0.1);
}

.miner-card:hover {
  border-color: rgba(255, 102, 170, 0.25);
}

.logo {
  background: linear-gradient(135deg, #ff66aa, #cc66ff, #66aaff);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
